const express = require('express');
const { MongoClient, ObjectId } = require('mongodb');

const ALLOWED_QUERY_OPERATORS = [
  '$eq', '$ne', '$gt', '$gte', '$lt', '$lte',
  '$in', '$nin', '$exists', '$type', '$mod',
  '$regex', '$options', '$text', '$search',
  '$all', '$elemMatch', '$size',
  '$and', '$or', '$not', '$nor'
];

const ALLOWED_PROJECTION_OPERATORS = [
  '$elemMatch', '$slice', '$meta'
];

const DANGEROUS_OPERATORS = ['$where', '$function', '$accumulator', '$expr'];

function sanitizeValue(value) {
  if (value === null || value === undefined) {
    return value;
  }

  if (typeof value === 'string') {
    return value.replace(/[^\w\s\-@.]/gi, (match) => {
      const safe = /^[a-zA-Z0-9\s\-@._]$/;
      return safe.test(match) ? match : '';
    });
  }

  if (typeof value === 'number' || typeof value === 'boolean') {
    return value;
  }

  if (Array.isArray(value)) {
    return value.map(sanitizeValue);
  }

  if (typeof value === 'object') {
    return sanitizeObject(value);
  }

  return value;
}

function sanitizeObject(obj, allowedOperators = ALLOWED_QUERY_OPERATORS) {
  if (!obj || typeof obj !== 'object' || Array.isArray(obj)) {
    return obj;
  }

  const sanitized = {};

  for (const [key, value] of Object.entries(obj)) {
    if (DANGEROUS_OPERATORS.includes(key)) {
      continue;
    }

    if (key.startsWith('$')) {
      if (!allowedOperators.includes(key)) {
        continue;
      }

      if (key === '$regex') {
        if (typeof value === 'string') {
          try {
            new RegExp(value);
            sanitized[key] = value.substring(0, 200);
          } catch (e) {
            continue;
          }
        }
      } else if (key === '$options') {
        if (typeof value === 'string' && /^[imxs]+$/.test(value)) {
          sanitized[key] = value;
        }
      } else if (key === '$in' || key === '$nin' || key === '$all') {
        if (Array.isArray(value)) {
          sanitized[key] = value.slice(0, 100).map(sanitizeValue);
        }
      } else if (key === '$and' || key === '$or' || key === '$nor') {
        if (Array.isArray(value)) {
          sanitized[key] = value.slice(0, 20).map(v => sanitizeObject(v, allowedOperators));
        }
      } else if (key === '$not') {
        sanitized[key] = sanitizeObject(value, allowedOperators);
      } else if (key === '$elemMatch') {
        sanitized[key] = sanitizeObject(value, allowedOperators);
      } else if (typeof value === 'object' && !Array.isArray(value)) {
        sanitized[key] = sanitizeObject(value, allowedOperators);
      } else {
        sanitized[key] = sanitizeValue(value);
      }
    } else {
      const sanitizedKey = key.replace(/^\$/, '').replace(/\./g, '_');

      if (typeof value === 'object' && value !== null && !Array.isArray(value)) {
        sanitized[sanitizedKey] = sanitizeObject(value, allowedOperators);
      } else {
        sanitized[sanitizedKey] = sanitizeValue(value);
      }
    }
  }

  return sanitized;
}

function sanitizeProjection(projection) {
  if (!projection || typeof projection !== 'object' || Array.isArray(projection)) {
    return {};
  }

  const sanitized = {};
  let hasInclusion = false;
  let hasExclusion = false;

  for (const [key, value] of Object.entries(projection)) {
    if (key.startsWith('$')) {
      continue;
    }

    const sanitizedKey = key.replace(/^\$/, '').replace(/\.\$/g, '');

    if (typeof value === 'object' && value !== null) {
      const projObj = {};
      for (const [opKey, opValue] of Object.entries(value)) {
        if (ALLOWED_PROJECTION_OPERATORS.includes(opKey)) {
          if (opKey === '$slice') {
            if (typeof opValue === 'number') {
              projObj[opKey] = Math.max(-1000, Math.min(1000, opValue));
            } else if (Array.isArray(opValue) && opValue.length === 2) {
              projObj[opKey] = [
                Math.max(0, Math.min(1000, opValue[0])),
                Math.max(0, Math.min(1000, opValue[1]))
              ];
            }
          } else if (opKey === '$elemMatch') {
            projObj[opKey] = sanitizeObject(opValue);
          }
        }
      }
      if (Object.keys(projObj).length > 0) {
        sanitized[sanitizedKey] = projObj;
      }
    } else if (value === 0 || value === 1 || value === false || value === true) {
      const numValue = value === true || value === 1 ? 1 : 0;
      
      if (numValue === 1) hasInclusion = true;
      if (numValue === 0) hasExclusion = true;

      if (sanitizedKey !== '_id' && hasInclusion && hasExclusion) {
        continue;
      }

      sanitized[sanitizedKey] = numValue;
    }
  }

  return sanitized;
}

function sanitizeSort(sort) {
  if (!sort || typeof sort !== 'object' || Array.isArray(sort)) {
    return {};
  }

  const sanitized = {};
  let count = 0;

  for (const [key, value] of Object.entries(sort)) {
    if (count >= 5) break;

    if (key.startsWith('$')) {
      continue;
    }

    const sanitizedKey = key.replace(/^\$/, '').replace(/\./g, '_');

    if (value === 1 || value === -1 || value === 'asc' || value === 'desc') {
      sanitized[sanitizedKey] = value === 'desc' || value === -1 ? -1 : 1;
      count++;
    }
  }

  return sanitized;
}

function queryBuilder(filter = {}, projection = {}, sort = {}) {
  const sanitizedFilter = sanitizeObject(filter, ALLOWED_QUERY_OPERATORS);
  const sanitizedProjection = sanitizeProjection(projection);
  const sanitizedSort = sanitizeSort(sort);

  return {
    filter: sanitizedFilter,
    projection: sanitizedProjection,
    sort: sanitizedSort
  };
}

const app = express();
app.use(express.json({ limit: '1mb' }));

let db;

MongoClient.connect('mongodb://localhost:27017', { useUnifiedTopology: true })
  .then(client => {
    db = client.db('admin_dashboard');
    console.log('Connected to MongoDB');
  })
  .catch(err => console.error('MongoDB connection error:', err));

app.post('/api/query/:collection', async (req, res) => {
  try {
    const { collection } = req.params;
    const { filter, projection, sort, limit = 100, skip = 0 } = req.body;

    const allowedCollections = ['users', 'products', 'orders', 'logs'];
    if (!allowedCollections.includes(collection)) {
      return res.status(400).json({ error: 'Invalid collection' });
    }

    const { filter: sanitizedFilter, projection: sanitizedProjection, sort: sanitizedSort } = 
      queryBuilder(filter, projection, sort);

    const sanitizedLimit = Math.min(Math.max(1, parseInt(limit) || 100), 1000);
    const sanitizedSkip = Math.max(0, parseInt(skip) || 0);

    const results = await db.collection(collection)
      .find(sanitizedFilter)
      .project(sanitizedProjection)
      .sort(sanitizedSort)
      .limit(sanitizedLimit)
      .skip(sanitizedSkip)
      .toArray();

    const total = await db.collection(collection).countDocuments(sanitizedFilter);

    res.json({
      success: true,
      data: results,
      total,
      limit: sanitizedLimit,
      skip: sanitizedSkip
    });

  } catch (error) {
    console.error('Query error:', error);
    res.status(500).json({ error: 'Query execution failed', message: error.message });
  }
});

